B.aab=new A.h([B.c,"\uc120\ud0dd\ud55c ZIP\uc5d0\ub294 \uc774 \uc2a4\ud0c0\uc77c\uc5d0 \ub9de\ub294 \uc774\ubbf8\uc9c0\uac00 \uc5c6\uc2b5\ub2c8\ub2e4. \ub2e4\ub978 \uc2a4\ud0c0\uc77c\uc758 \ud329\uc744 \uc798\ubabb \uace0\ub974\uc168\ub294\uc9c0 \ud655\uc778\ud574\uc8fc\uc138\uc694.",B.e,"The selected ZIP contains no images for this style. Did you pick a different style's pack by mistake?",B.d,"\u9078\u629e\u3057\u305fZIP\u306b\u3053\u306e\u30b9\u30bf\u30a4\u30eb\u306e\u753b\u50cf\u304c\u3042\u308a\u307e\u305b\u3093\u3002\u5225\u30b9\u30bf\u30a4\u30eb\u306e\u30d1\u30c3\u30af\u3092\u9078\u3093\u3067\u3044\u306a\u3044\u304b\u78ba\u8a8d\u3057\u3066\u304f\u3060\u3055\u3044\u3002"],t.C)
